ALLOWED_DIRS = [Path.home() / 'Desktop', Path.home() / 'Downloads', Path.home() / 'Pictures']
MAX_FILE_SIZE = 50 * 1024 * 1024  # 50MB

def validate_image_path(image_path: str) -> Path:
    p = Path(image_path).resolve()
    if not any(str(p).startswith(str(d.resolve())) for d in ALLOWED_DIRS):
        raise ValueError(f"Path not in allowed directories: {p}")
    if p.stat().st_size > MAX_FILE_SIZE:
        raise ValueError("File too large")
    return p

def preprocess(path):
    p = Path(path).resolve()
    if not p.exists():
        raise FileNotFoundError(f"Image not found: {p}")
    if p.stat().st_size > 50 * 1024 * 1024:
        raise ValueError("Image file too large (max 50MB)")
    data = p.read_bytes()

